CREATE TABLE branches (id INTEGER PRIMARY KEY, name TEXT NOT NULL, active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL);
CREATE TABLE users (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), name TEXT NOT NULL, username TEXT NOT NULL, pwd_hash TEXT NOT NULL, role TEXT NOT NULL CHECK (role IN ('owner','manager','cashier')), active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, UNIQUE(branch_id, username));
CREATE TABLE user_branches (user_id INTEGER NOT NULL REFERENCES users(id), branch_id INTEGER NOT NULL REFERENCES branches(id), PRIMARY KEY (user_id, branch_id));
CREATE TABLE accounts (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), name TEXT NOT NULL, platform TEXT, acct_type TEXT NOT NULL CHECK (acct_type IN ('digital','cash')), active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL);
CREATE TABLE txn_types (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), name TEXT NOT NULL, cash_effect TEXT NOT NULL CHECK (cash_effect IN ('in','out','none')), digital_effect TEXT NOT NULL CHECK (digital_effect IN ('in','out','none')), active INTEGER NOT NULL DEFAULT 1);
CREATE TABLE fee_rules (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), platform TEXT NOT NULL, min_amount_pya INTEGER NOT NULL DEFAULT 0, max_amount_pya INTEGER, fee_pct REAL NOT NULL, min_fee_pya INTEGER NOT NULL DEFAULT 0, comm_pct REAL NOT NULL DEFAULT 0, effective_from TEXT, active INTEGER NOT NULL DEFAULT 1);
CREATE TABLE counterparties (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), name TEXT NOT NULL, cp_type TEXT NOT NULL CHECK (cp_type IN ('agent','customer')), phone TEXT, created_at TEXT NOT NULL);
CREATE TABLE daily_closes (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), business_date TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open','closed')), expected_cash_pya INTEGER, actual_cash_pya INTEGER, discrepancy_pya INTEGER, reason TEXT, closed_at TEXT, closed_by INTEGER REFERENCES users(id), UNIQUE (branch_id, business_date));
CREATE TABLE ledger_entries (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), account_id INTEGER NOT NULL REFERENCES accounts(id), to_account_id INTEGER REFERENCES accounts(id), type_id INTEGER NOT NULL REFERENCES txn_types(id), amount_pya INTEGER NOT NULL, fee_pya INTEGER NOT NULL DEFAULT 0, commission_pya INTEGER NOT NULL DEFAULT 0, cash_delta_pya INTEGER NOT NULL DEFAULT 0, digital_delta_pya INTEGER NOT NULL DEFAULT 0, sender_phone TEXT, receiver_phone TEXT, ref_no TEXT, note TEXT, counterparty_id INTEGER REFERENCES counterparties(id), reverses_id INTEGER REFERENCES ledger_entries(id), created_at TEXT NOT NULL, created_by INTEGER NOT NULL REFERENCES users(id));
CREATE INDEX ix_entries_branch_date ON ledger_entries(branch_id, created_at);
CREATE INDEX ix_entries_account ON ledger_entries(account_id);
CREATE TRIGGER ledger_no_update BEFORE UPDATE ON ledger_entries BEGIN SELECT RAISE(ABORT,'ledger_entries is append-only'); END;
CREATE TRIGGER ledger_no_delete BEFORE DELETE ON ledger_entries BEGIN SELECT RAISE(ABORT,'ledger_entries is append-only'); END;
CREATE TABLE debts (id INTEGER PRIMARY KEY, branch_id INTEGER NOT NULL REFERENCES branches(id), counterparty_id INTEGER NOT NULL REFERENCES counterparties(id), kind TEXT NOT NULL CHECK (kind IN ('receivable','payable')), original_pya INTEGER NOT NULL, source_entry_id INTEGER REFERENCES ledger_entries(id), due_at TEXT, status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open','settled')), created_at TEXT NOT NULL, created_by INTEGER NOT NULL REFERENCES users(id));
CREATE TABLE debt_payments (id INTEGER PRIMARY KEY, debt_id INTEGER NOT NULL REFERENCES debts(id), amount_pya INTEGER NOT NULL, paid_at TEXT NOT NULL, paid_by INTEGER NOT NULL REFERENCES users(id), entry_id INTEGER REFERENCES ledger_entries(id));
CREATE TABLE daily_close_lines (id INTEGER PRIMARY KEY, close_id INTEGER NOT NULL REFERENCES daily_closes(id), account_id INTEGER NOT NULL REFERENCES accounts(id), expected_pya INTEGER NOT NULL, actual_pya INTEGER NOT NULL, diff_pya INTEGER NOT NULL);
CREATE TABLE activity_log (id INTEGER PRIMARY KEY, branch_id INTEGER REFERENCES branches(id), ts TEXT NOT NULL, user_id INTEGER REFERENCES users(id), action TEXT NOT NULL, detail TEXT);
CREATE TABLE backups (id INTEGER PRIMARY KEY, ts TEXT NOT NULL, location TEXT NOT NULL, size_bytes INTEGER, sha256 TEXT, verified INTEGER NOT NULL DEFAULT 0, created_by INTEGER REFERENCES users(id));
CREATE TABLE settings (branch_id INTEGER REFERENCES branches(id), key TEXT NOT NULL, value TEXT, PRIMARY KEY (branch_id, key));
CREATE TABLE app_meta (key TEXT PRIMARY KEY, value TEXT);